Onlay.elements=[];function Onlay(option={}){this.opt=Object.assign({closeMethods:["button","overlay","escape"],destroyOnClose:true,cssClass:[],footer:false},option);this.template=document.querySelector(`#${this.opt.templateId}`);if(!this.template){console.error("template id none exits");return}this._allowButtonClose=this.opt.closeMethods.includes("button");this._allowBackdropClose=this.opt.closeMethods.includes("overlay");this._allowEscapeClose=this.opt.closeMethods.includes("escape");this._footerButton=[]}Onlay.prototype._createElement=function(){const content=this.template.content.cloneNode(true);this._backdrop=document.createElement("div");this._backdrop.className="onlay__backdrop";const container=document.createElement("div");container.className="onlay__container";if(this.opt.cssClass.length>0){this.opt.cssClass.forEach(className=>{if(typeof className==="string"){container.classList.add(className)}})}if(this._allowButtonClose){const btnClose=this._createButton("&times;","onlay__close",()=>this.close());container.append(btnClose)}const modelContent=document.createElement("div");modelContent.className="onlay__content";modelContent.append(content);container.append(modelContent);this._backdrop.append(container);document.body.append(this._backdrop);if(this.opt.footer){this._modelFooter=document.createElement("div");this._modelFooter.className="onlay__footer";this._renderFooterContent();this._renderButton();container.append(this._modelFooter)}};Onlay.prototype.open=function(){Onlay.elements.push(this);if(!this._backdrop){this._createElement()}setTimeout(()=>{this._backdrop.classList.add("onlay__backdrop--show")},0);if(this._allowBackdropClose){this._backdrop.onclick=e=>{if(e.target===this._backdrop){this.close()}}}this._handelEscapeClose=e=>{const lastModel=Onlay.elements[Onlay.elements.length-1];if(e.key==="Escape"&&this===lastModel){this.close()}};if(this._allowEscapeClose){document.addEventListener("keydown",this._handelEscapeClose)}document.body.classList.add("onlay--no-scroll");document.body.style.paddingRight=this._getScrollBar()+"px";this._onTransitionEnd(this.opt.onOpen);return this._backdrop};Onlay.prototype.close=function(destroy=this.opt.destroyOnClose){if(this._allowEscapeClose){document.removeEventListener("keydown",this._handelEscapeClose)}Onlay.elements.pop();this._backdrop.classList.remove("onlay__backdrop--show");this._onTransitionEnd(()=>{this._backdrop.ontransitionend=null;if(destroy&&this._backdrop){this._backdrop.remove();this._backdrop=null;this._modelFooter=null}if(typeof this.opt.onClose==="function"){this.opt.onClose()}if(!Onlay.elements.length){document.body.classList.remove("onlay--no-scroll");document.body.style.paddingRight=""}})};Onlay.prototype.destroy=function(){this.close(true)};Onlay.prototype._onTransitionEnd=function(callback){this._backdrop.ontransitionend=e=>{if(e.propertyName!=="transform")return;if(typeof callback==="function"){callback()}}};Onlay.prototype._getScrollBar=function(){if(this._scrollBarWidth!==undefined)return this._scrollBarWidth;const div=document.createElement("div");div.style.position="absolute";div.style.top="-999px";div.style.width="100px";div.style.height="100px";div.style.overflow="scroll";document.body.appendChild(div);this._scrollBarWidth=div.offsetWidth-div.clientWidth;document.body.removeChild(div);return this._scrollBarWidth};Onlay.prototype.setFooterContent=function(html){this._footerContent=html;this._renderFooterContent()};Onlay.prototype.addFooterButton=function(title,className,callback){const btn=this._createButton(title,className,callback);this._footerButton.push(btn);this._renderButton()};Onlay.prototype._createButton=function(title,className,callback){const btn=document.createElement("button");btn.className=className;btn.innerHTML=title;btn.onclick=callback;return btn};Onlay.prototype._renderButton=function(){if(this._footerButton.length>0&&this._modelFooter){this._footerButton.forEach(btn=>{this._modelFooter.append(btn)})}};Onlay.prototype._renderFooterContent=function(){if(this._modelFooter&&this._footerContent){this._modelFooter.innerHTML=this._footerContent}};